// Package s3 provides a WAF bundle fetcher for PLM's S3-compatible storage (SeaweedFS).
package s3

import (
	"context"
	"crypto/sha256"
	"crypto/tls"
	"crypto/x509"
	"encoding/hex"
	"errors"
	"fmt"
	"io"
	"net/http"
	"strings"

	"github.com/aws/aws-sdk-go-v2/aws"
	awsconfig "github.com/aws/aws-sdk-go-v2/config"
	"github.com/aws/aws-sdk-go-v2/credentials"
	"github.com/aws/aws-sdk-go-v2/service/s3"
	"github.com/go-logr/logr"

	sharedsecrets "github.com/nginx/nginx-gateway-fabric/v2/internal/controller/state/graph/shared/secrets"
)

// Credentials holds S3 auth credentials resolved from Kubernetes Secrets.
type Credentials struct {
	// AccessKeyID is the S3 access key ID.
	AccessKeyID string
	// SecretAccessKey is the S3 secret access key.
	SecretAccessKey string
}

// TLSConfig holds TLS configuration resolved from Kubernetes Secrets.
type TLSConfig struct {
	// CAData is the PEM-encoded CA certificate for verifying the S3 endpoint.
	CAData []byte
	// CertData is the PEM-encoded client certificate for mutual TLS.
	CertData []byte
	// KeyData is the PEM-encoded client private key for mutual TLS.
	KeyData []byte
}

// Fetcher downloads WAF bundles from PLM's S3-compatible storage (SeaweedFS).
type Fetcher struct {
	logger     logr.Logger
	endpoint   string
	skipVerify bool
}

// NewFetcher creates a new S3 fetcher for the given endpoint.
// The endpoint and skipVerify are fixed at startup from CLI flags.
func NewFetcher(logger logr.Logger, endpoint string, skipVerify bool) *Fetcher {
	return &Fetcher{
		logger:     logger,
		endpoint:   endpoint,
		skipVerify: skipVerify,
	}
}

// FetchBundle downloads a bundle from the given S3 location and verifies its SHA-256 checksum.
// A new S3 client is constructed per call with the provided credentials and TLS config
// (fetches are infrequent and event-driven, so client caching is unnecessary).
// The location must be an s3:// URI (e.g. "s3://bucket/path/bundle.tgz").
// creds may be nil for anonymous access; tlsCfg may be nil to use system CAs.
func (f *Fetcher) FetchBundle(
	ctx context.Context,
	location string,
	expectedSHA256 string,
	creds *Credentials,
	tlsCfg *TLSConfig,
) ([]byte, error) {
	bucket, key, err := parseS3URI(location)
	if err != nil {
		return nil, fmt.Errorf("invalid S3 location: %w", err)
	}

	client, err := f.buildClient(ctx, creds, tlsCfg)
	if err != nil {
		return nil, fmt.Errorf("failed to build S3 client: %w", err)
	}

	f.logger.V(1).Info(
		"Fetching PLM bundle from S3",
		"bucket", bucket,
		"key", key,
	)

	result, err := client.GetObject(ctx, &s3.GetObjectInput{
		Bucket: aws.String(bucket),
		Key:    aws.String(key),
	})
	if err != nil {
		return nil, fmt.Errorf("S3 GetObject failed for %s: %w", location, err)
	}
	defer result.Body.Close()

	data, err := io.ReadAll(result.Body)
	if err != nil {
		return nil, fmt.Errorf("failed to read S3 object body: %w", err)
	}

	if expectedSHA256 != "" {
		actualHash := sha256.Sum256(data)
		actualHex := hex.EncodeToString(actualHash[:])
		if !strings.EqualFold(actualHex, expectedSHA256) {
			return nil, fmt.Errorf(
				"SHA-256 mismatch for %s: expected %s, got %s",
				location,
				expectedSHA256,
				actualHex,
			)
		}
	}

	f.logger.V(1).Info(
		"Successfully fetched PLM bundle",
		"bucket", bucket,
		"key", key,
		"size", len(data),
	)

	return data, nil
}

// parseS3URI parses an s3://bucket/key URI into bucket and key components.
func parseS3URI(uri string) (bucket, key string, err error) {
	if uri == "" {
		return "", "", fmt.Errorf("empty S3 URI")
	}

	if !strings.HasPrefix(uri, "s3://") {
		return "", "", fmt.Errorf("URI must start with s3://: %s", uri)
	}

	path := strings.TrimPrefix(uri, "s3://")
	if path == "" {
		return "", "", fmt.Errorf("missing bucket in S3 URI: %s", uri)
	}

	slashIdx := strings.IndexByte(path, '/')
	if slashIdx < 0 || slashIdx == len(path)-1 {
		return "", "", fmt.Errorf("missing key in S3 URI: %s", uri)
	}

	bucket = path[:slashIdx]
	key = path[slashIdx+1:]

	if bucket == "" {
		return "", "", fmt.Errorf("empty bucket in S3 URI: %s", uri)
	}

	if key == "" {
		return "", "", fmt.Errorf("empty key in S3 URI: %s", uri)
	}

	return bucket, key, nil
}

// buildClient creates a new S3 client with the provided credentials and TLS configuration.
func (f *Fetcher) buildClient(
	ctx context.Context,
	creds *Credentials,
	tlsCfg *TLSConfig,
) (*s3.Client, error) {
	// Validate the fully assembled TLS config at the fetcher boundary. Secret resolution only
	// checks Secret shape/presence so it can log which Kubernetes Secret is misconfigured.
	if err := validateTLSConfig(tlsCfg); err != nil {
		return nil, fmt.Errorf("invalid TLS configuration: %w", err)
	}

	var opts []func(*awsconfig.LoadOptions) error

	// Set credentials
	if creds != nil && creds.AccessKeyID != "" {
		opts = append(opts, awsconfig.WithCredentialsProvider(
			credentials.NewStaticCredentialsProvider(
				creds.AccessKeyID,
				creds.SecretAccessKey,
				"",
			),
		))
	} else {
		opts = append(opts, awsconfig.WithCredentialsProvider(aws.AnonymousCredentials{}))
	}

	// Build TLS config
	transport, err := buildTLSTransport(tlsCfg, f.skipVerify)
	if err != nil {
		return nil, fmt.Errorf("failed to build TLS transport: %w", err)
	}
	if transport != nil {
		opts = append(opts, awsconfig.WithHTTPClient(&http.Client{
			Transport: transport,
		}))
	}

	// Use a dummy region since SeaweedFS doesn't care about regions
	opts = append(opts, awsconfig.WithRegion("us-east-1"))

	cfg, err := awsconfig.LoadDefaultConfig(ctx, opts...)
	if err != nil {
		return nil, fmt.Errorf("failed to load AWS config: %w", err)
	}

	client := s3.NewFromConfig(cfg, func(o *s3.Options) {
		o.BaseEndpoint = aws.String(f.endpoint)
		o.UsePathStyle = true // Required for SeaweedFS
	})

	return client, nil
}

// buildTLSTransport creates an HTTP transport with custom TLS configuration.
// It clones http.DefaultTransport to preserve default proxy/timeout/connection-reuse settings
// and appends any custom CA to the system cert pool.
// Returns (nil, nil) if no custom TLS is needed.
func buildTLSTransport(tlsCfg *TLSConfig, skipVerify bool) (*http.Transport, error) {
	if tlsCfg == nil && !skipVerify {
		return nil, nil //nolint:nilnil // nil transport means "use default", not an error
	}

	defaultTransport, ok := http.DefaultTransport.(*http.Transport)
	if !ok {
		return nil, fmt.Errorf("http.DefaultTransport is not *http.Transport")
	}
	transport := defaultTransport.Clone()
	transport.TLSClientConfig = &tls.Config{
		MinVersion:         tls.VersionTLS12,
		InsecureSkipVerify: skipVerify, //nolint:gosec // controlled by CLI flag
	}

	if tlsCfg != nil {
		if len(tlsCfg.CAData) > 0 {
			pool, err := x509.SystemCertPool()
			if err != nil {
				pool = x509.NewCertPool()
			}
			if !pool.AppendCertsFromPEM(tlsCfg.CAData) {
				return nil, fmt.Errorf("failed to append CA certificate to pool")
			}
			transport.TLSClientConfig.RootCAs = pool
		}

		if len(tlsCfg.CertData) > 0 && len(tlsCfg.KeyData) > 0 {
			cert, err := tls.X509KeyPair(tlsCfg.CertData, tlsCfg.KeyData)
			if err != nil {
				return nil, fmt.Errorf("failed to load client TLS key pair: %w", err)
			}
			transport.TLSClientConfig.Certificates = []tls.Certificate{cert}
		}
	}

	return transport, nil
}

func validateTLSConfig(tlsCfg *TLSConfig) error {
	// This validates TLS semantics for the assembled client config. It intentionally does not
	// know about individual Kubernetes Secrets; that context is handled during secret resolution.
	if tlsCfg == nil {
		return nil
	}

	if len(tlsCfg.CAData) > 0 {
		if err := sharedsecrets.ValidateCA(tlsCfg.CAData); err != nil {
			return fmt.Errorf("invalid CA bundle: %w", err)
		}
	}

	hasCert := len(tlsCfg.CertData) > 0
	hasKey := len(tlsCfg.KeyData) > 0

	if hasCert != hasKey {
		return errors.New("client certificate and key must both be provided")
	}

	if hasCert {
		if err := sharedsecrets.ValidateTLS(tlsCfg.CertData, tlsCfg.KeyData); err != nil {
			return fmt.Errorf("invalid client certificate or key: %w", err)
		}
	}

	return nil
}

package poller

import (
	"context"
	"maps"
	"sync"

	"github.com/go-logr/logr"
	metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
	"k8s.io/apimachinery/pkg/types"

	"github.com/nginx/nginx-gateway-fabric/v2/internal/controller/nginx/agent"
	"github.com/nginx/nginx-gateway-fabric/v2/internal/controller/state/graph"
	"github.com/nginx/nginx-gateway-fabric/v2/internal/framework/events"
	"github.com/nginx/nginx-gateway-fabric/v2/internal/framework/waf/fetch"
)

//go:generate go tool counterfeiter -generate

// PollError represents a polling error for a specific bundle.
type PollError struct {
	Err error
	// BundleKey is the internal identifier of the bundle that failed.
	BundleKey graph.WAFBundleKey
	// BundleDescription is a human-readable label for the bundle,
	// e.g. "policy bundle" or "security log bundle (profile: default)".
	BundleDescription string
}

// BundleUpdate records the most recent poll cycle in which a changed bundle was detected and
// dispatched to target deployments. It does not confirm that any deployment applied the update.
type BundleUpdate struct {
	UpdatedAt metav1.Time
	// BundleKey is the internal identifier of the bundle that was updated.
	BundleKey graph.WAFBundleKey
	// BundleDescription is a human-readable label for the bundle,
	// e.g. "policy bundle" or "security log bundle (profile: default)".
	BundleDescription string
	Checksum          string
}

// Manager is the interface for managing WAF bundle pollers.
//
//counterfeiter:generate . Manager
type Manager interface {
	// ReconcilePoller ensures a poller is running with the correct configuration.
	ReconcilePoller(ctx context.Context, cfg Config)
	// GetAllPollErrors returns a deep copy of all current poll errors.
	GetAllPollErrors() map[types.NamespacedName]PollError
	// GetAllBundleUpdates returns a copy of the most recent bundle change detected per policy.
	GetAllBundleUpdates() map[types.NamespacedName]BundleUpdate
	// GetLatestBundles returns a copy of all bundles that have been successfully fetched by pollers.
	// These represent the freshest known bundle data and should take precedence over
	// graph-cached bundles when constructing stale-bundle fallback state.
	GetLatestBundles() map[graph.WAFBundleKey]*graph.WAFBundleData
	// StopPoller stops the poller for a WAFPolicy.
	StopPoller(policyNsName types.NamespacedName)
	// StopPollersNotIn stops all pollers whose policy namespace/name is not in the given set.
	StopPollersNotIn(activePolicies map[types.NamespacedName]struct{})
	// HasPoller reports whether a poller is currently registered for the given policy.
	HasPoller(policyNsName types.NamespacedName) bool
}

// pollerManager manages the lifecycle of all WAF bundle pollers.
// It creates, tracks, and stops pollers as WAFPolicies are created, updated, or deleted.
type pollerManager struct {
	fetcher       fetch.Fetcher
	deployments   agent.DeploymentStorer
	pollers       map[types.NamespacedName]*pollerEntry
	pollErrors    map[types.NamespacedName]*PollError
	bundleUpdates map[types.NamespacedName]BundleUpdate
	bundleCache   map[graph.WAFBundleKey]*graph.WAFBundleData
	// bundleKeyToPolicy maps each bundle key to the policy that owns it.
	// Used to look up the policy namespace/name when injecting a WAFBundleReconcileEvent.
	bundleKeyToPolicy map[graph.WAFBundleKey]types.NamespacedName
	// bundleKeyToDescription maps each bundle key to a human-readable description of the bundle,
	// e.g. "policy bundle" or "security log bundle (profile: default)".
	// Used to produce user-visible condition messages without exposing internal key formats.
	bundleKeyToDescription map[graph.WAFBundleKey]string
	statusCallback         func(targets []types.NamespacedName)
	// eventCh is the send side of the main event loop channel.
	// A WAFBundleReconcileEvent is sent when a previously-pending bundle is first fetched successfully,
	// triggering an immediate re-reconcile so the Gateway config push can proceed.
	eventCh chan<- any
	// ctx is the root context for the manager, used to cancel goroutines on shutdown.
	ctx    context.Context
	logger logr.Logger
	mu     sync.RWMutex
}

// pollerEntry holds a poller and its cancellation function.
type pollerEntry struct {
	poller *poller
	cancel context.CancelFunc
}

// ManagerConfig contains configuration for creating a new Manager.
type ManagerConfig struct {
	Fetcher        fetch.Fetcher
	Deployments    agent.DeploymentStorer
	StatusCallback func(targets []types.NamespacedName)
	EventCh        chan<- any
	// Ctx is the root context for the manager lifetime.
	// It is used to cancel goroutines that inject events into the event loop on shutdown.
	Ctx    context.Context
	Logger logr.Logger
}

// NewManager creates a new Manager.
// It panics if EventCh is set without Ctx, as the event-injection goroutine requires
// a context to avoid leaking on shutdown.
func NewManager(cfg ManagerConfig) Manager {
	if cfg.EventCh != nil && cfg.Ctx == nil {
		panic("waf.ManagerConfig: Ctx must be set when EventCh is set")
	}
	return &pollerManager{
		logger:                 cfg.Logger,
		fetcher:                cfg.Fetcher,
		deployments:            cfg.Deployments,
		pollers:                make(map[types.NamespacedName]*pollerEntry),
		pollErrors:             make(map[types.NamespacedName]*PollError),
		bundleUpdates:          make(map[types.NamespacedName]BundleUpdate),
		bundleCache:            make(map[graph.WAFBundleKey]*graph.WAFBundleData),
		bundleKeyToPolicy:      make(map[graph.WAFBundleKey]types.NamespacedName),
		bundleKeyToDescription: make(map[graph.WAFBundleKey]string),
		statusCallback:         cfg.StatusCallback,
		eventCh:                cfg.EventCh,
		ctx:                    cfg.Ctx,
	}
}

// Config contains configuration for reconciling a poller.
type Config struct {
	InitialChecksums  map[graph.WAFBundleKey]string
	PolicyNsName      types.NamespacedName
	Sources           []BundleSource
	TargetDeployments []types.NamespacedName
}

// ReconcilePoller ensures a poller is running with the correct configuration.
// If no poller exists, one is started. If a poller exists with the same sources,
// only the target deployments are updated. If sources have changed, the poller is restarted.
// This avoids unnecessary poller restarts when only targets change.
func (m *pollerManager) ReconcilePoller(ctx context.Context, cfg Config) {
	if len(cfg.Sources) == 0 {
		m.logger.V(1).Info("No polling sources, not starting poller", "policy", cfg.PolicyNsName)
		return
	}

	m.mu.Lock()
	entry, exists := m.pollers[cfg.PolicyNsName]

	// If poller exists and sources haven't changed, just update targets if needed.
	if exists && sourcesEqual(entry.poller.getSources(), cfg.Sources) {
		m.mu.Unlock()
		entry.poller.updateTargetDeployments(cfg.TargetDeployments)
		return
	}
	m.mu.Unlock()

	// Sources changed or poller doesn't exist - need to (re)start.
	m.startPoller(ctx, cfg)
}

// startPoller starts a new poller, stopping any existing one first.
func (m *pollerManager) startPoller(ctx context.Context, cfg Config) {
	m.mu.Lock()
	defer m.mu.Unlock()

	// Always cancel any existing poller before overwriting the map entry.
	// This is safe even if the caller didn't observe one, because another
	// goroutine may have started one between our check and acquiring this lock.
	if entry, exists := m.pollers[cfg.PolicyNsName]; exists {
		m.logger.V(1).Info("Stopping existing poller before starting new one", "policy", cfg.PolicyNsName)
		entry.cancel()
		delete(m.pollErrors, cfg.PolicyNsName)
		delete(m.bundleUpdates, cfg.PolicyNsName)
		m.clearBundleCacheLocked(entry.poller)
	}

	pollerCtx, cancel := context.WithCancel(ctx)

	var poller *poller

	// Create a wrapped callback that records poll results and triggers a status update
	// scoped to just the poller's target deployments.
	wrappedCallback := func(
		policyNsName types.NamespacedName,
		bundleKey graph.WAFBundleKey,
		newChecksum string,
		err error,
	) {
		m.mu.RLock()
		desc := m.bundleKeyToDescription[bundleKey]
		m.mu.RUnlock()
		if desc == "" {
			desc = "WAF bundle"
		}
		m.recordPollResult(policyNsName, bundleKey, desc, newChecksum, err)
		if m.statusCallback != nil {
			m.statusCallback(poller.getTargetDeployments())
		}
	}

	// Record which policy owns each bundle key and its human-readable description.
	for _, src := range cfg.Sources {
		m.bundleKeyToPolicy[src.BundleKey] = cfg.PolicyNsName
		desc := src.Description
		if desc == "" {
			desc = "WAF bundle"
		}
		m.bundleKeyToDescription[src.BundleKey] = desc
	}

	poller = newPoller(pollerConfig{
		logger:               m.logger,
		policyNsName:         cfg.PolicyNsName,
		sources:              cfg.Sources,
		fetcher:              m.fetcher,
		deployments:          m.deployments,
		targetDeployments:    cfg.TargetDeployments,
		initialChecksums:     cfg.InitialChecksums,
		statusCallback:       wrappedCallback,
		bundleUpdateCallback: m.cacheBundleUpdate,
	})

	m.pollers[cfg.PolicyNsName] = &pollerEntry{
		poller: poller,
		cancel: cancel,
	}

	go func() {
		poller.run(pollerCtx)
		// Clean up after poller exits.
		m.mu.Lock()
		// Only delete if this is still the same poller (could have been replaced).
		if entry, exists := m.pollers[cfg.PolicyNsName]; exists && entry.poller == poller {
			delete(m.pollers, cfg.PolicyNsName)
		}
		m.mu.Unlock()
	}()

	m.logger.Info("Started WAF poller", "policy", cfg.PolicyNsName, "sourceCount", len(cfg.Sources))
}

// recordPollResult records the result of a poll attempt for a policy.
// If err is nil, it clears any previous error for the same bundle key.
// If newChecksum is non-empty, the bundle was successfully updated and the update is recorded.
// If err is non-nil, it stores the error for this bundle key.
// This method is called by the internal status callback.
func (m *pollerManager) recordPollResult(
	policyNsName types.NamespacedName,
	bundleKey graph.WAFBundleKey,
	bundleDescription string,
	newChecksum string,
	err error,
) {
	m.mu.Lock()
	defer m.mu.Unlock()

	if err == nil {
		if existing := m.pollErrors[policyNsName]; existing != nil && existing.BundleKey == bundleKey {
			delete(m.pollErrors, policyNsName)
		}
		if newChecksum != "" {
			m.bundleUpdates[policyNsName] = BundleUpdate{
				BundleKey:         bundleKey,
				BundleDescription: bundleDescription,
				Checksum:          newChecksum,
				UpdatedAt:         metav1.Now(),
			}
		}
	} else {
		m.pollErrors[policyNsName] = &PollError{
			BundleKey:         bundleKey,
			BundleDescription: bundleDescription,
			Err:               err,
		}
	}
}

// GetAllBundleUpdates returns a copy of the most recent successful bundle update per policy.
func (m *pollerManager) GetAllBundleUpdates() map[types.NamespacedName]BundleUpdate {
	m.mu.RLock()
	defer m.mu.RUnlock()

	if len(m.bundleUpdates) == 0 {
		return nil
	}

	result := make(map[types.NamespacedName]BundleUpdate, len(m.bundleUpdates))
	maps.Copy(result, m.bundleUpdates)
	return result
}

// cacheBundleUpdate stores the latest successfully polled bundle data in the manager's cache.
// This is called by pollers when they detect a changed bundle, ensuring the freshest data
// is available for graph rebuild stale-bundle fallback.
// On the first time a bundle key appears in this manager's cache, a WAFBundleReconcileEvent
// is injected into the event loop to trigger an immediate graph rebuild.
// Note: this fires on any first-cache event, including after a poller restart that cleared the
// cache — not only when the policy was previously in BundlePending state. A spurious reconcile
// event in that case is harmless: it triggers an unnecessary graph rebuild but causes no
// incorrect behavior.
func (m *pollerManager) cacheBundleUpdate(bundleKey graph.WAFBundleKey, data []byte, checksum string) {
	m.mu.Lock()

	_, alreadyCached := m.bundleCache[bundleKey]

	m.bundleCache[bundleKey] = &graph.WAFBundleData{
		Data:     data,
		Checksum: checksum,
	}

	// Capture event details while holding the lock, then release before sending.
	var event *events.WAFBundleReconcileEvent
	if !alreadyCached {
		if policyNsName, ok := m.bundleKeyToPolicy[bundleKey]; ok && m.eventCh != nil {
			event = &events.WAFBundleReconcileEvent{PolicyNsName: policyNsName}
		}
	}

	m.mu.Unlock()

	// Send the reconcile event after releasing the lock so other manager operations are not
	// blocked on the mutex while waiting for the event loop. The manager's root context is
	// used as a cancellation escape hatch: on shutdown, the event loop exits before the
	// manager's context is canceled, so without this the poller goroutine could block
	// indefinitely trying to send to an already-drained channel.
	if event != nil {
		select {
		case m.eventCh <- *event:
		case <-m.ctx.Done():
		}
	}
}

// GetAllPollErrors returns a deep copy of all current poll errors.
func (m *pollerManager) GetAllPollErrors() map[types.NamespacedName]PollError {
	m.mu.RLock()
	defer m.mu.RUnlock()

	if len(m.pollErrors) == 0 {
		return nil
	}

	result := make(map[types.NamespacedName]PollError, len(m.pollErrors))
	for k, v := range m.pollErrors {
		result[k] = *v
	}
	return result
}

// GetLatestBundles returns a copy of all bundles that have been successfully fetched by pollers.
// These represent the freshest known bundle data and should take precedence over
// graph-cached bundles when constructing stale-bundle fallback state.
func (m *pollerManager) GetLatestBundles() map[graph.WAFBundleKey]*graph.WAFBundleData {
	m.mu.RLock()
	defer m.mu.RUnlock()

	if len(m.bundleCache) == 0 {
		return nil
	}

	result := make(map[graph.WAFBundleKey]*graph.WAFBundleData, len(m.bundleCache))
	maps.Copy(result, m.bundleCache)
	return result
}

// StopPoller stops the poller for a WAFPolicy.
func (m *pollerManager) StopPoller(policyNsName types.NamespacedName) {
	m.mu.Lock()
	entry, exists := m.pollers[policyNsName]
	if !exists {
		m.mu.Unlock()
		return
	}
	delete(m.pollers, policyNsName)
	delete(m.pollErrors, policyNsName)
	delete(m.bundleUpdates, policyNsName)
	m.clearBundleCacheLocked(entry.poller)
	m.mu.Unlock()

	entry.cancel()
	m.logger.Info("Stopped WAF poller", "policy", policyNsName)
}

// stopAll stops all running pollers. Should be called during shutdown.
func (m *pollerManager) stopAll() {
	m.mu.Lock()
	entries := make([]*pollerEntry, 0, len(m.pollers))
	for _, entry := range m.pollers {
		entries = append(entries, entry)
	}
	m.pollers = make(map[types.NamespacedName]*pollerEntry)
	m.pollErrors = make(map[types.NamespacedName]*PollError)
	m.bundleUpdates = make(map[types.NamespacedName]BundleUpdate)
	m.bundleCache = make(map[graph.WAFBundleKey]*graph.WAFBundleData)
	m.bundleKeyToPolicy = make(map[graph.WAFBundleKey]types.NamespacedName)
	m.bundleKeyToDescription = make(map[graph.WAFBundleKey]string)
	m.mu.Unlock()

	for _, entry := range entries {
		entry.cancel()
	}

	m.logger.Info("Stopped all WAF pollers", "count", len(entries))
}

// clearBundleCacheLocked removes cached bundle data and all per-key mappings for all bundle keys
// owned by the given poller. Must be called while m.mu is held.
func (m *pollerManager) clearBundleCacheLocked(p *poller) {
	for _, src := range p.getSources() {
		delete(m.bundleCache, src.BundleKey)
		delete(m.bundleKeyToPolicy, src.BundleKey)
		delete(m.bundleKeyToDescription, src.BundleKey)
	}
}

// HasPoller reports whether a poller is currently registered for the given policy.
func (m *pollerManager) HasPoller(policyNsName types.NamespacedName) bool {
	m.mu.RLock()
	defer m.mu.RUnlock()
	_, exists := m.pollers[policyNsName]
	return exists
}

// StopPollersNotIn stops all pollers whose policy namespace/name is not in the given set.
// This is used to clean up pollers for policies that have been deleted or no longer need polling.
func (m *pollerManager) StopPollersNotIn(activePolicies map[types.NamespacedName]struct{}) {
	m.mu.Lock()
	var toStop []types.NamespacedName
	for nsName := range m.pollers {
		if _, active := activePolicies[nsName]; !active {
			toStop = append(toStop, nsName)
		}
	}

	entriesToCancel := make([]*pollerEntry, 0, len(toStop))
	for _, nsName := range toStop {
		if entry, exists := m.pollers[nsName]; exists {
			entriesToCancel = append(entriesToCancel, entry)
			delete(m.pollers, nsName)
			delete(m.pollErrors, nsName)
			delete(m.bundleUpdates, nsName)
			m.clearBundleCacheLocked(entry.poller)
		}
	}
	m.mu.Unlock()

	for _, entry := range entriesToCancel {
		entry.cancel()
	}

	if len(toStop) > 0 {
		m.logger.Info("Stopped stale WAF pollers", "count", len(toStop))
	}
}

package poller

import (
	"context"
	"fmt"
	"reflect"
	"sync"
	"time"

	"github.com/go-logr/logr"
	"k8s.io/apimachinery/pkg/types"

	ngfAPIv1alpha1 "github.com/nginx/nginx-gateway-fabric/v2/apis/v1alpha1"
	"github.com/nginx/nginx-gateway-fabric/v2/internal/controller/nginx/agent"
	"github.com/nginx/nginx-gateway-fabric/v2/internal/controller/nginx/config"
	"github.com/nginx/nginx-gateway-fabric/v2/internal/controller/state/dataplane"
	"github.com/nginx/nginx-gateway-fabric/v2/internal/controller/state/graph"
	"github.com/nginx/nginx-gateway-fabric/v2/internal/framework/waf/fetch"
)

// defaultPollingInterval is the default interval between poll cycles.
const defaultPollingInterval = 5 * time.Minute

type BundleType int

const (
	PolicyBundle BundleType = iota
	LogProfileBundle
)

// BundleSource represents a single bundle source that needs polling.
// This can be either the main policy bundle or a log bundle.
type BundleSource struct {
	// BundleKey is the unique identifier for this bundle.
	BundleKey graph.WAFBundleKey
	// Description is a human-readable label for this bundle, used in status conditions and log messages.
	Description string
	// Request contains the fetch configuration for this bundle.
	Request fetch.Request
	// Type indicates whether this is a policy bundle or a log profile bundle, which determines the fetch method used.
	Type BundleType
	// Interval is the polling interval for this source.
	Interval time.Duration
}

// bundleState tracks the last known state of a fetched bundle, including the checksum and any
// conditional-request validators (ETag or Last-Modified) for use on subsequent HTTP polls.
type bundleState struct {
	checksum     string
	eTag         string
	lastModified string
}

// poller handles periodic re-fetching of WAF bundles for a single WAFPolicy.
// It compares checksums to detect changes and pushes updated bundles to relevant deployments.
type poller struct {
	fetcher           fetch.Fetcher
	deployments       agent.DeploymentStorer
	targetDeployments map[types.NamespacedName]struct{}
	bundleStates      map[graph.WAFBundleKey]bundleState
	statusCallback    func(
		policyNsName types.NamespacedName,
		bundleKey graph.WAFBundleKey,
		newChecksum string,
		err error,
	)
	bundleUpdateCallback func(bundleKey graph.WAFBundleKey, data []byte, checksum string)
	policyNsName         types.NamespacedName
	logger               logr.Logger
	sources              []BundleSource
	targetMu             sync.RWMutex
	stateMu              sync.RWMutex
}

// pollerConfig contains the configuration for creating a new poller.
type pollerConfig struct {
	fetcher          fetch.Fetcher
	deployments      agent.DeploymentStorer
	initialChecksums map[graph.WAFBundleKey]string
	statusCallback   func(
		policyNsName types.NamespacedName,
		bundleKey graph.WAFBundleKey,
		newChecksum string,
		err error,
	)
	bundleUpdateCallback func(bundleKey graph.WAFBundleKey, data []byte, checksum string)
	policyNsName         types.NamespacedName
	logger               logr.Logger
	sources              []BundleSource
	targetDeployments    []types.NamespacedName
}

// newPoller creates a new poller for the given WAFPolicy.
func newPoller(cfg pollerConfig) *poller {
	targets := make(map[types.NamespacedName]struct{}, len(cfg.targetDeployments))
	for _, t := range cfg.targetDeployments {
		targets[t] = struct{}{}
	}

	states := make(map[graph.WAFBundleKey]bundleState, len(cfg.initialChecksums))
	for k, cs := range cfg.initialChecksums {
		states[k] = bundleState{checksum: cs}
	}

	return &poller{
		logger:               cfg.logger.WithValues("policy", cfg.policyNsName),
		policyNsName:         cfg.policyNsName,
		sources:              cfg.sources,
		fetcher:              cfg.fetcher,
		deployments:          cfg.deployments,
		targetDeployments:    targets,
		bundleStates:         states,
		statusCallback:       cfg.statusCallback,
		bundleUpdateCallback: cfg.bundleUpdateCallback,
	}
}

// run starts the polling loop. It blocks until the context is canceled.
func (p *poller) run(ctx context.Context) {
	if len(p.sources) == 0 {
		p.logger.V(1).Info("No sources with polling enabled, poller exiting")
		return
	}

	// Find the minimum interval among all sources to use as the tick interval.
	minInterval := p.sources[0].Interval
	for _, src := range p.sources[1:] {
		minInterval = min(minInterval, src.Interval)
	}

	if minInterval <= 0 {
		p.logger.Error(nil, fmt.Sprintf(
			"Invalid polling interval, must be greater than zero. Using default interval: %v", defaultPollingInterval,
		))
		minInterval = defaultPollingInterval
	}

	p.logger.Info("WAF polling started", "interval", minInterval, "sourceCount", len(p.sources))

	// Track last poll time for each source to handle different intervals.
	lastPoll := make(map[graph.WAFBundleKey]time.Time, len(p.sources))

	// Poll all sources immediately on startup, then start the ticker for subsequent polls.
	now := time.Now()
	for _, src := range p.sources {
		p.pollSource(ctx, src)
		lastPoll[src.BundleKey] = now
	}

	ticker := time.NewTicker(minInterval)
	defer ticker.Stop()

	for {
		select {
		case <-ctx.Done():
			p.logger.V(1).Info("Poller stopping due to context cancellation")
			return
		case now := <-ticker.C:
			for _, src := range p.sources {
				if now.Sub(lastPoll[src.BundleKey]) >= src.Interval {
					p.pollSource(ctx, src)
					lastPoll[src.BundleKey] = now
				}
			}
		}
	}
}

// getTargetDeployments returns the current set of target deployment names.
func (p *poller) getTargetDeployments() []types.NamespacedName {
	p.targetMu.RLock()
	defer p.targetMu.RUnlock()

	targets := make([]types.NamespacedName, 0, len(p.targetDeployments))
	for t := range p.targetDeployments {
		targets = append(targets, t)
	}

	return targets
}

// updateTargetDeployments updates the set of deployments this poller should push bundles to.
func (p *poller) updateTargetDeployments(targets []types.NamespacedName) {
	newTargets := make(map[types.NamespacedName]struct{}, len(targets))
	for _, t := range targets {
		newTargets[t] = struct{}{}
	}

	p.targetMu.Lock()
	defer p.targetMu.Unlock()

	p.targetDeployments = newTargets
}

// getSources returns the bundle sources this poller is monitoring.
func (p *poller) getSources() []BundleSource {
	return p.sources
}

// sourcesEqual returns true if two BundleSource slices are equivalent.
// This is used to determine if a poller needs to be restarted due to source changes.
func sourcesEqual(a, b []BundleSource) bool {
	return reflect.DeepEqual(a, b)
}

// pollSource fetches a single bundle source and pushes it to deployments if changed.
//
// For NIM and N1C sources a two-phase approach is used: first only the remote checksum is
// retrieved, and the full bundle is downloaded only when the checksum differs from the last
// known value.
//
// For plain HTTP sources a conditional GET is issued using any ETag or Last-Modified token
// stored from the previous successful fetch. A 304 Not Modified response is treated as
// unchanged without downloading the bundle.
func (p *poller) pollSource(ctx context.Context, src BundleSource) {
	p.logger.V(1).Info("Polling bundle source", "bundle", src.BundleKey)

	p.stateMu.RLock()
	last := p.bundleStates[src.BundleKey]
	p.stateMu.RUnlock()

	if src.Request.SupportsChecksumOnlyFetch() {
		if skip := p.skipIfChecksumUnchanged(ctx, src, last.checksum); skip {
			return
		}
	}

	result, err := p.downloadBundle(ctx, src, last)
	if err != nil {
		p.reportStatus(src.BundleKey, "", err)
		return
	}

	if result.Unchanged {
		// 304 Not Modified: content is the same. Preserve the existing checksum and persist
		// any rotated ETag/Last-Modified the server sent back so future polls can use it.
		result.Checksum = last.checksum
		p.saveBundleState(src.BundleKey, result)
		p.reportStatus(src.BundleKey, "", nil)
		return
	}

	if result.Checksum == last.checksum {
		// Content is identical but the server may have rotated its conditional token (ETag /
		// Last-Modified). Save the new token so the next poll can use it, avoiding a full
		// re-download every interval when the validator changes while content stays the same.
		p.saveBundleState(src.BundleKey, result)
		p.reportStatus(src.BundleKey, "", nil)
		return
	}

	p.logger.Info("Bundle changed, pushing to deployments", "bundle", src.BundleKey, "newChecksum", result.Checksum)
	p.pushBundleToDeployments(src.BundleKey, result.Data)
	p.saveBundleState(src.BundleKey, result)

	if p.bundleUpdateCallback != nil {
		p.bundleUpdateCallback(src.BundleKey, result.Data, result.Checksum)
	}
	p.reportStatus(src.BundleKey, result.Checksum, nil)
}

// skipIfChecksumUnchanged fetches only the remote checksum for a NIM or N1C source.
// It reports whether polling should skip the full download (true = skip). When skipping due to
// an error or an unchanged checksum the appropriate status callback is fired.
func (p *poller) skipIfChecksumUnchanged(ctx context.Context, src BundleSource, lastChecksum string) bool {
	changed, checksum, err := p.checksumChanged(ctx, src, lastChecksum)
	if err != nil {
		p.logger.Error(err, "Failed to fetch bundle checksum during poll", "bundle", src.BundleKey)
		p.reportStatus(src.BundleKey, "", err)
		return true
	}
	if !changed {
		p.logger.V(1).Info("Bundle unchanged, skipping download", "bundle", src.BundleKey)
		p.reportStatus(src.BundleKey, "", nil)
		return true
	}
	p.logger.Info("Bundle checksum changed, downloading full bundle", "bundle", src.BundleKey, "newChecksum", checksum)
	return false
}

// downloadBundle fetches the full bundle for src, attaching the stored conditional token so that
// HTTP servers can respond with 304 Not Modified when nothing has changed.
func (p *poller) downloadBundle(
	ctx context.Context, src BundleSource, last bundleState,
) (fetch.Result, error) {
	req := src.Request
	req.ETag = last.eTag
	req.LastModified = last.lastModified

	result, err := p.fetchBundle(ctx, src, req)
	if err != nil {
		p.logger.Error(err, "Failed to fetch bundle during poll", "bundle", src.BundleKey)
		return fetch.Result{}, err
	}
	if result.Unchanged {
		p.logger.V(1).Info("Bundle unchanged (304), skipping push", "bundle", src.BundleKey)
	} else if result.Checksum == last.checksum {
		p.logger.V(1).Info("Bundle unchanged, skipping push", "bundle", src.BundleKey)
	}
	return result, nil
}

// saveBundleState persists the checksum and HTTP conditional token after a successful fetch,
// including when no push occurs because the content is unchanged but the conditional token rotated.
// A previously stored conditional token is preserved when the response does not supply a new one,
// so that servers omitting validators on some responses do not force unconditional GETs.
func (p *poller) saveBundleState(bundleKey graph.WAFBundleKey, result fetch.Result) {
	p.stateMu.Lock()
	defer p.stateMu.Unlock()

	state := p.bundleStates[bundleKey]
	state.checksum = result.Checksum
	if result.ETag != "" {
		state.eTag = result.ETag
	}
	if result.LastModified != "" {
		state.lastModified = result.LastModified
	}
	// If ETag or Last-Modified is absent in the response, the previously stored value is preserved
	// so that servers omitting validators on some responses do not force unconditional GETs.
	p.bundleStates[bundleKey] = state
}

// reportStatus fires the status callback if one is registered.
// newChecksum is non-empty when the bundle was successfully updated; empty for unchanged or error cases.
func (p *poller) reportStatus(bundleKey graph.WAFBundleKey, newChecksum string, err error) {
	if p.statusCallback != nil {
		p.statusCallback(p.policyNsName, bundleKey, newChecksum, err)
	}
}

// checksumChanged fetches only the remote checksum for a NIM or N1C source and reports whether
// it differs from lastChecksum. Returns (changed, remoteChecksum, error).
func (p *poller) checksumChanged(ctx context.Context, src BundleSource, lastChecksum string) (bool, string, error) {
	var checksum string
	var err error

	if src.Type == LogProfileBundle {
		checksum, err = p.fetcher.FetchLogProfileBundleChecksum(ctx, src.Request)
	} else {
		checksum, err = p.fetcher.FetchPolicyBundleChecksum(ctx, src.Request)
	}
	if err != nil {
		return false, "", err
	}

	return checksum != lastChecksum, checksum, nil
}

// fetchBundle downloads the full bundle for the given source using req (which may carry a
// conditional token for HTTP sources).
func (p *poller) fetchBundle(ctx context.Context, src BundleSource, req fetch.Request) (fetch.Result, error) {
	if src.Type == LogProfileBundle {
		return p.fetcher.FetchLogProfileBundle(ctx, req)
	}
	return p.fetcher.FetchPolicyBundle(ctx, req)
}

// pushBundleToDeployments pushes the bundle to all target deployments.
func (p *poller) pushBundleToDeployments(bundleKey graph.WAFBundleKey, data []byte) {
	p.targetMu.RLock()
	defer p.targetMu.RUnlock()

	bundlePath := config.GenerateWAFBundleFileName(dataplane.WAFBundleID(bundleKey))

	for depName := range p.targetDeployments {
		deployment := p.deployments.Get(depName)
		if deployment == nil {
			p.logger.V(1).Info("Deployment not found, skipping bundle push", "deployment", depName)
			continue
		}

		deployment.FileLock.Lock()
		msg := deployment.UpdateWAFBundle(bundlePath, data)
		if msg != nil {
			applied := deployment.GetBroadcaster().Send(*msg)
			if applied {
				p.logger.Info(
					"Pushed updated WAF bundle to deployment",
					"deployment", depName,
				)
			} else {
				p.logger.V(1).Info(
					"No subscribers for deployment, bundle stored but not pushed",
					"deployment", depName,
				)
			}
		}
		deployment.FileLock.Unlock()
	}
}

// BuildBundleSources constructs BundleSource entries from a WAFPolicy spec.
// It returns only sources that have polling enabled.
func BuildBundleSources(
	policyNsName types.NamespacedName,
	spec ngfAPIv1alpha1.WAFPolicySpec,
	auth *fetch.BundleAuth,
	tlsCA []byte,
) []BundleSource {
	var sources []BundleSource

	// Check if policySource has polling enabled.
	if spec.PolicySource != nil && spec.PolicySource.Polling != nil && spec.PolicySource.Polling.Enabled {
		interval := defaultPollingInterval
		if spec.PolicySource.Polling.Interval != nil && spec.PolicySource.Polling.Interval.Duration > 0 {
			interval = spec.PolicySource.Polling.Interval.Duration
		}

		sources = append(sources, BundleSource{
			Type:        PolicyBundle,
			BundleKey:   graph.PolicyBundleKey(policyNsName),
			Request:     graph.BuildPolicyFetchRequest(spec.PolicySource, spec.Type, auth, tlsCA),
			Description: "policy bundle",
			Interval:    interval,
		})
	}

	// Check each logSource for polling.
	for _, secLog := range spec.SecurityLogs {
		if secLog.LogSource == nil {
			continue
		}
		if secLog.LogSource.HTTPSource == nil && secLog.LogSource.NIMSource == nil && secLog.LogSource.N1CSource == nil {
			continue // DefaultProfile, no polling needed.
		}
		if secLog.LogSource.Polling == nil || !secLog.LogSource.Polling.Enabled {
			continue
		}

		interval := defaultPollingInterval
		if secLog.LogSource.Polling.Interval != nil && secLog.LogSource.Polling.Interval.Duration > 0 {
			interval = secLog.LogSource.Polling.Interval.Duration
		}

		sources = append(sources, BundleSource{
			Type:        LogProfileBundle,
			BundleKey:   graph.LogBundleKey(policyNsName, secLog.LogSource),
			Request:     graph.BuildLogFetchRequest(secLog.LogSource, auth, tlsCA),
			Description: graph.LogBundleDescription(secLog.LogSource),
			Interval:    interval,
		})
	}

	return sources
}

